import { IErrorResponse } from '@domain/error';
import { PublicActionPage } from '@domain/publicActionPage';
import { ApiClient } from '@service/anedot/client';
import { generateQueryKey, resourceKeys } from '@state/cacheHelper';
import { makeSearchParams } from '@utils/params/makeSearchParams';
import { useQuery } from 'react-query';

export const useShowActionPage = ({
  accountSlug,
  actionPageSlug,
  customDomain,
}: {
  accountSlug?: string;
  actionPageSlug?: string;
  customDomain?: string;
}): {
  actionPage?: PublicActionPage;
  error: IErrorResponse | undefined | null;
  isError: boolean;
  isFetched: boolean;
  isLoading: boolean;
} => {
  const params = makeSearchParams({
    account_slug: accountSlug,
    custom_domain: customDomain,
  });

  const query = useQuery<PublicActionPage, IErrorResponse>(
    generateQueryKey({
      accountId: accountSlug,
      resourceId: actionPageSlug,
      resourceKey: resourceKeys.actionPagesShow,
    }),
    () => {
      return new ApiClient({ namespace: 'public' }).get<PublicActionPage>(
        `/action_pages/${actionPageSlug}?${params.toString()}`
      );
    },
    {
      enabled: !!actionPageSlug && (!!accountSlug || !!customDomain),
      retry: false,
    }
  );

  return {
    actionPage: query.data,
    error: query.error,
    isError: query.isLoading,
    isFetched: query.isFetched,
    isLoading: query.isLoading,
  };
};

