import { useShowActionPage } from '@state/action_pages/queries/useShowActionPage';
import { getBasePaths } from '@ui/utils/getBasePaths';
import { isDevelopment } from '@utils';
import { lazy, useEffect } from 'react';
import { useParams, useSearchParams } from 'react-router-dom';
import { ActionPageLayout } from './ActionPageLayout';

import './ActionPageView.css';

const EventActionPageView = lazy(
  () => import('../../../../../builder/PublicActionPage/ActionPageView/ActionPageView.js')
);

type Props = {
  isRestricted?: boolean;
};

const { basePath } = getBasePaths();
const favIconPath = isDevelopment() ? '/favicon.png' : '/uiv2/favicon.png';

export const ActionPageView = ({ isRestricted = false }: Props) => {
  const [searchParams] = useSearchParams();
  const isEmbedded = searchParams.get('embed') === 'true';

  const { accountSlug, actionPageSlug } = useParams<{
    accountSlug: string;
    actionPageSlug: string;
  }>();

  const { actionPage, isFetched } = useShowActionPage({
    accountSlug,
    actionPageSlug,
    customDomain: !accountSlug ? window.location.hostname : undefined,
  });

  if (!actionPage && isFetched) {
    window.location.href = `${basePath}/404`;
  }

  useEffect(() => {
    const favIconUrl =
      actionPage?.favIcon?.file?.small?.url ||
      actionPage?.account.favIcon?.file?.small?.url ||
      favIconPath;
    const favIconElement = document.getElementById('favicon');

    (favIconElement as HTMLLinkElement).href = favIconUrl;
  }, [actionPage]);

  // If it's an event page, render the event page view
  if (actionPage?.pageType === 'event') {
    return <EventActionPageView isRestricted={isRestricted} />;
  }

  // Otherwise render the regular action page view
  return (
    <ActionPageLayout
      actionPage={actionPage}
      isCustomDomain={!accountSlug}
      isEmbedded={isEmbedded}
      isRestricted={isRestricted}
    />
  );
};

export default ActionPageView;
